def findSubstring(s, words):
    if not s or not words: return []
    wl, m, n = len(words[0]), len(words), len(s); res = []; counts = collections.Counter(words)
    for i in range(wl):
        l = i; d = collections.defaultdict(int); cnt = 0
        for r in range(i, n - wl + 1, wl):
            w = s[r:r+wl]
            if w in counts:
                d[w] += 1; cnt += 1
                while d[w] > counts[w]: d[s[l:l+wl]] -= 1; cnt -= 1; l += wl
                if cnt == m: res.append(l)
            else: d.clear(); cnt = 0; l = r + wl
    return res

